kotlin_syntax.cheat:
// Basics
val x: Int = 42
var y = 10
fun sum(a: Int, b: Int) = a + b
// Lambda
val doubled = list.map { it * 2 }
// Data class
data class User(val id: Int, val name: String)
// Sealed + when
sealed class Result { data class Ok(val v: Int): Result(); data class Err(val e: String): Result() }
when (r) { is Result.Ok -> r.v; is Result.Err -> r.e }

kotlin_nullsafety.cheat:
// Nullable examples
val s: String? = null
val len = s?.length ?: 0
s?.let { println(it) }
// Unsafe
val mustNotNull: String = s!!  // throws NPE if s is null

examples.code:
fun displayName(user: User?) {
  val name = user?.name ?: "guest"
  println(name)
}

kotlin_coroutines.cheat:
// Basic coroutine
import kotlinx.coroutines.*
GlobalScope.launch { val data = async { fetch() }.await(); println(data) }

// Scoped
runBlocking { launch(Dispatchers.IO) { /* IO work */ } }

// Flow
flowOf(1,2,3).map { it * 2 }.collect { println(it) }

kotlin_collections.cheat:
// Common ops
val nums = listOf(1,2,3)
val doubled = nums.map { it * 2 }
val grouped = nums.groupBy { it % 2 }
// Sequence
val seq = nums.asSequence().map { heavy(it) }.filter { it > 10 }.toList()

examples.code:
val names = listOf("Alice","Bob","Carol")
val byLen = names.groupBy { it.length }
println(byLen)

kotlin_oop_functional.cheat:
// Immutability
data class User(val id: Int, val name: String)
val updated = user.copy(name = "New")
// Extension
fun String.isEmail() = this.contains("@")
// Higher-order
fun operate(a: Int, b: Int, op: (Int, Int) -> Int) = op(a,b)

kotlin_generics.cheat:
// Generic example
class Box<T>(val value: T)
fun <T> listOfOne(item: T) = listOf(item)
// Reified
inline fun <reified T> Gson.fromJson(json: String) = this.fromJson<T>(json, T::class.java)

